from typing import Callable, Optional, TypeVar

# Define a TypeVar for generic numeric types (int or float)
T = TypeVar('T', int, float)


class UnionFind:
    """
    A Disjoint Set Union (DSU) data structure with path compression and union by rank.

    This data structure maintains a collection of disjoint sets and provides efficient
    operations for merging sets (union) and finding the representative (root)
    of the set to which an element belongs (find). It is 0-indexed.
    """

    def __init__(self, n: int):
        """
        Initializes the Union-Find structure for `n` elements.
        Each element is initially in its own set.

        Args:
            n: The number of elements (0-indexed) to manage.
        """
        if n < 0:
            raise ValueError("Number of elements must be non-negative.")
        self._parent = list(range(n))
        self._rank = [0] * n  # Used for union by rank heuristic
        self._num_components = n

    def find(self, i: int) -> int:
        """
        Finds the representative (root) of the set containing element `i`.
        Performs path compression to flatten the tree structure, making future
        find operations faster.

        Args:
            i: The element whose set representative is to be found.

        Returns:
            The representative (root) of the set containing `i`.
        
        Raises:
            IndexError: If the element index `i` is out of bounds.
        """
        if not (0 <= i < len(self._parent)):
            raise IndexError(f"Element index {i} out of bounds for {len(self._parent)} elements.")
        if self._parent[i] == i:
            return i
        # Path compression: set parent[i] directly to the root
        self._parent[i] = self.find(self._parent[i])
        return self._parent[i]

    def union(self, i: int, j: int) -> bool:
        """
        Unites the sets containing elements `i` and `j`.
        Uses union by rank heuristic to keep the tree flat, attaching the
        shorter tree under the root of the taller tree.

        Args:
            i: The first element.
            j: The second element.

        Returns:
            True if the sets were different and successfully merged, False otherwise
            (they were already in the same set).
        
        Raises:
            IndexError: If either element index `i` or `j` is out of bounds.
        """
        if not (0 <= i < len(self._parent)) or not (0 <= j < len(self._parent)):
            raise IndexError(f"Element indices ({i}, {j}) out of bounds for {len(self._parent)} elements.")

        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            # Union by rank: attach smaller rank tree under root of larger rank tree
            if self._rank[root_i] < self._rank[root_j]:
                self._parent[root_i] = root_j
            elif self._rank[root_j] < self._rank[root_i]:
                self._parent[root_j] = root_i
            else:
                # Ranks are equal, choose one root and increment its rank
                self._parent[root_j] = root_i
                self._rank[root_i] += 1
            self._num_components -= 1
            return True
        return False

    def connected(self, i: int, j: int) -> bool:
        """
        Checks if two elements `i` and `j` belong to the same set (i.e., are connected).

        Args:
            i: The first element.
            j: The second element.

        Returns:
            True if `i` and `j` are in the same set, False otherwise.
        
        Raises:
            IndexError: If either element index `i` or `j` is out of bounds.
        """
        if not (0 <= i < len(self._parent)) or not (0 <= j < len(self._parent)):
            raise IndexError(f"Element indices ({i}, {j}) out of bounds for {len(self._parent)} elements.")
        return self.find(i) == self.find(j)

    def get_num_components(self) -> int:
        """
        Returns the current number of disjoint sets (connected components).

        Returns:
            The total number of distinct sets.
        """
        return self._num_components

