def binary_search_predicate(
    low: T,
    high: T,
    predicate: Callable[[T], bool],
    find_min_true: bool = True,
    iterations: int = 100 # For float precision/safety; integer search loop is low <= high
) -> Optional[T]:
    """
    Performs a binary search on a range [low, high] to find a value that satisfies a predicate function.

    This function is useful when searching for a specific value 'x' where a boolean function
    `predicate(x)` changes its truth value monotonically.
    - If `find_min_true` is True: Searches for the minimum `x` for which `predicate(x)` is True.
      The predicate should follow a `F, F, F, T, T, T` pattern (monotonic non-decreasing).
    - If `find_min_true` is False: Searches for the maximum `x` for which `predicate(x)` is True.
      The predicate should follow a `T, T, T, F, F, F` pattern (monotonic non-increasing).

    Args:
        low: The lower bound of the search range (inclusive).
        high: The upper bound of the search range (inclusive).
        predicate: A callable that takes a value (T) and returns a boolean.
                   Its behavior should be monotonic as described above.
        find_min_true: If True (default), searches for the minimum `x` in the range
                       such that `predicate(x)` is True.
                       If False, searches for the maximum `x` in the range
                       such that `predicate(x)` is True.
        iterations: For floating point searches, this determines the number of refinements.
                    A value of 100-200 is typically sufficient for good precision.
                    For integer searches, this parameter is effectively ignored as the loop
                    terminates when `low > high`.

    Returns:
        The found value `x` if one exists in the range and satisfies the predicate.
        Returns None if no such value is found.
    """
    ans: Optional[T] = None
    
    is_integer_search = isinstance(low, int) and isinstance(high, int)

    if find_min_true: # Searching for the smallest 'x' where predicate(x) is True
        while (is_integer_search and low <= high) or (not is_integer_search and iterations > 0):
            mid: T
            if is_integer_search:
                mid = low + (high - low) // 2
            else:
                mid = low + (high - low) / 2
            
            if predicate(mid):
                ans = mid # mid is a potential candidate
                high = mid - (1 if is_integer_search else 0) # Try to find an even smaller 'mid'
            else:
                low = mid + (1 if is_integer_search else 0) # 'mid' is too small, look higher
            
            if not is_integer_search:
                iterations -= 1
        
        # After loop, if ans is not None, it's the smallest 'x' that satisfied predicate(x)
        # We perform an additional check with predicate(ans) to handle cases where
        # `ans` might have been set to an initial 'low' or 'high' for convenience,
        # but technically no valid 'x' was found within the actual search process
        # (e.g. if the entire range is False).
        return ans if ans is not None and predicate(ans) else None
    
    else: # find_max_true: Searching for the largest 'x' where predicate(x) is True
        while (is_integer_search and low <= high) or (not is_integer_search and iterations > 0):
            mid: T
            if is_integer_search:
                # For finding max, bias mid upwards to prevent infinite loops when `low`
                # might become `mid` and `high` doesn't change (e.g., [0,1], mid=0, P(0)=T, low=0)
                mid = low + (high - low + 1) // 2
            else:
                mid = low + (high - low) / 2
            
            if predicate(mid):
                ans = mid # mid is a potential candidate
                low = mid + (1 if is_integer_search else 0) # 'mid' is a candidate, try larger values
            else:
                high = mid - (1 if is_integer_search else 0) # 'mid' is too large, look lower
            
            if not is_integer_search:
                iterations -= 1
        
        # Similar validation for ans as in find_min_true
        return ans if ans is not None and predicate(ans) else None

